#include <bits/stdc++.h>
using namespace std;

const int N=8003;

int n,p[N],c[N],ans[N];

int lowbit(int x){
    return x&(-x);
}

int query(int x){
    int sum=0;
    for(;x;x-=lowbit(x))
        sum+=c[x];
    return sum;
}

void modify(int x){
    for(;x<=n;x+=lowbit(x))
        c[x]--;
}

int Find(int x){
    int l=1,r=n;
    while(l<r){
        int mid=l+r>>1;
        if(query(mid)>x)
            r=mid;
        else
            l=mid+1;
    }
    return l;
}

int main(){
    scanf("%d",&n);
    for(int i=2;i<=n;i++)
        scanf("%d",&p[i]);
    for(int i=1;i<=n;i++)
        c[i]=lowbit(i);
    for(int i=n;i;i--)
        ans[i]=Find(p[i]),modify(ans[i]);
    for(int i=1;i<=n;i++)
        printf("%d\n",ans[i]);
    return 0;
}
